<div class="form-group"><label>Expected Turnover (Year 1)</label><select id="inTurnover"><option value="10">Below &#8377;10L</option><option value="40" selected>&#8377;10L&ndash;40L</option><option value="200">&#8377;40L&ndash;2Cr</option><option value="500">Above &#8377;2Cr</option></select></div>
