<script>
function getVal(id){var g=document.getElementById(id);var a=g.querySelector('.toggle-btn.active');return a?a.getAttribute('data-val'):'';}
function setTg(gid,btn){var g=document.getElementById(gid);g.querySelectorAll('.toggle-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');}
function resetForm(){['prioLiab','prioFund'].forEach(function(g){document.getElementById(g).querySelectorAll('.toggle-btn').forEach(function(b,i){b.classList.toggle('active',i===0);});});document.getElementById('inTurnover').value='40';document.getElementById('inFounders').value='2';document.getElementById('resPanel').classList.remove('visible');}
function compare(){
var liab=getVal('prioLiab')==='high',fund=getVal('prioFund')==='yes';
var to=parseInt(document.getElementById('inTurnover').value),founders=parseInt(document.getElementById('inFounders').value);
var rec='',reason='',alt='';
if(fund){rec='Private Limited Company';reason='Only Pvt Ltd allows equity funding from VCs, angel investors, and PE firms. Essential for startups seeking investment.';}
else if(founders===1&&to<=200&&!fund){rec='One Person Company (OPC)';reason='Perfect for solo founders with limited liability protection. No partner needed. Turnover cap of \u20B92Cr applies.';}
else if(liab&&!fund&&to<=200){rec='LLP';reason='Limited liability with lower compliance than Pvt Ltd. No mandatory audit below \u20B940L turnover. Ideal for professional firms and small businesses.';}
else if(!liab&&to<=40){rec='Partnership Firm';reason='Simplest structure with minimal compliance. However, partners have unlimited personal liability for business debts.';}
else{rec='Private Limited Company';reason='Best for growth-oriented businesses. Limited liability, perpetual succession, and full funding access.';}
if(rec==='Private Limited Company')alt='LLP';else if(rec==='LLP')alt='Private Limited Company';else if(rec==='OPC')alt='LLP';else alt='LLP';
var h='<div class="res-hero"><div class="res-box eligible"><div class="rb-label">Recommended Structure</div><div class="rb-value">'+rec+'</div><div class="rb-sub">Based on your priorities</div></div><div class="res-box rate"><div class="rb-label">Alternative</div><div class="rb-value">'+alt+'</div><div class="rb-sub">Consider if priorities change</div></div></div>';
h+='<div class="callout green"><p><strong>Why '+rec+':</strong> '+reason+'</p></div>';
h+='<div class="res-actions"><a href="https://wa.me/919459456700?text=Hi%2C%20I%20want%20to%20register%20a%20'+encodeURIComponent(rec)+'.%20Please%20help." target="_blank" class="ra-btn"><svg viewBox="0 0 24 24" fill="#25D366" width="18" height="18"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347z"/></svg> Register Now</a></div>';
document.getElementById('resBody').innerHTML=h;document.getElementById('resPanel').classList.add('visible');document.getElementById('resPanel').scrollIntoView({behavior:'smooth',block:'start'});}

var FAQS=[{q:"What is the best business structure?",a:"Depends on goals. Pvt Ltd for funding/growth. LLP for professionals with lower compliance. OPC for solo founders. Partnership for simple small businesses. Consider liability, funding, and compliance budget."},{q:"Pvt Ltd vs LLP?",a:"Pvt Ltd: 25% tax, best for VC funding, higher compliance. LLP: 30% tax, lower compliance, no audit < ₹40L. Pvt Ltd for startups, LLP for professional firms."},{q:"Minimum capital for Pvt Ltd?",a:"No minimum. Start with ₹1L authorized capital. Increase later. Most startups begin at ₹1L to minimise cost."},{q:"Can OPC convert to Pvt Ltd?",a:"Yes. Mandatory if turnover > \u20B92Cr or capital > \u20B950L. Voluntary anytime. Takes 15\u201330 days via MCA forms. Under Companies Act Section 18, conversion requires at least 2 shareholders and 2 directors."},{q:"What is unlimited liability?",a:"Partners’ personal assets at risk for business debts. Biggest disadvantage of partnership and sole proprietorship vs Pvt Ltd/LLP."},{q:"Which has lowest compliance?",a:"Sole prop: zero ROC. Partnership: minimal. LLP: 2 forms/year. Pvt Ltd: highest (AGM, audit, ROC filings). Choose based on willingness to invest."},{q:"Best structure for tax saving?",a:"Pvt Ltd at 25% flat for profit > ₹12–15L. Below that, sole prop slab rates may be lower. LLP/Partnership at 30% is higher."},{q:"Can foreigners start business?",a:"Foreigners can direct Pvt Ltd. LLP needs 1 resident partner. FDI easiest in Pvt Ltd. Partnership/sole prop not available to foreigners."},{q:"Registration timeline?",a:"Pvt Ltd: 7\u201315 days. OPC: 7\u201315 days. LLP: 10\u201320 days. Partnership: 1\u20137 days. Sole prop: same day. Peak filing season (March/September) may add 5\u20137 extra days."},{q:"Need a CA for registration?",a:"Not mandatory but recommended. Reduces rejection risk. Fees: \u20B93K (partnership) to \u20B915K (Pvt Ltd). Self-filing possible but error-prone. Over 90% of Indian company registrations are filed through professionals."},{q:"What is perpetual succession?",a:"Company exists regardless of member changes/death. Pvt Ltd, OPC, LLP have it. Partnership dissolves on partner death unless deed specifies otherwise."},{q:"Can I change structure later?",a:"Yes. Sole prop → Pvt Ltd. Partnership → LLP/Pvt Ltd. OPC → Pvt Ltd. Each has specific MCA forms and fees. Plan right from start."},{q:"Cheapest business to start?",a:"Sole prop: ₹0–2K. Partnership: ₹1K–5K. For limited liability: LLP at ₹5K–12K. Consider long-term costs not just registration."}];


function buildFAQ(){var list=document.getElementById('faqList');if(!list)return;FAQS.forEach(function(faq){var item=document.createElement('div');item.className='faq-item';item.innerHTML='<button class="faq-question" onclick="toggleFaq(this)"><span>'+faq.q+'</span><span class="faq-icon">+</span></button><div class="faq-answer"><div class="faq-answer-inner">'+faq.a+'</div></div>';list.appendChild(item);});}
function toggleFaq(btn){var item=btn.closest('.faq-item');var o=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');});if(!o)item.classList.add('open');}
var navLinks=document.querySelectorAll('.toc-nav a');window.addEventListener('scroll',function(){var cur='';document.querySelectorAll('[id]').forEach(function(s){if(pageYOffset>=s.offsetTop-80)cur=s.getAttribute('id');});navLinks.forEach(function(l){l.classList.toggle('active',l.getAttribute('href')==='#'+cur);});});
document.addEventListener('DOMContentLoaded',function(){buildFAQ();if(typeof initTool==='function')initTool();});

